/* Version script for libflashmaskv2.so
 *
 * Only export flashmaskv2_* public API symbols.
 * Hide all statically-linked nvshmem internals to prevent
 * symbol interposition with other shared libraries (DeepEP) when both
 * .so files coexist in the same process.
 */
{
    global:
        flashmaskv2_*;
    local:
        *;
};
